// Type inference
var name = 'Dart';

// Explicit typing
String message = 'Hello, Dart!';

// Dynamic type
dynamic anything = 42;

// Final and const
final pi = 3.14;
const maxUsers = 100;

// Normal function
int add(int a, int b) {
  return a + b;
}

// Arrow syntax
int multiply(int a, int b) => a * b;

// Optional parameters
void greet(String name, [String? title]) {
  print('Hello $title $name');
}

// Named parameters
void createUser({required String name, int age = 0}) {
  print('User: $name, age: $age');
}

class Person {
  String name;
  int age;

  Person(this.name, this.age);

  void sayHello() {
    print('Hi, I am $name');
  }
}

void main() {
  var p = Person('Alice', 30);
  p.sayHello();
}

// Lists
var list = [1, 2, 3];
list.add(4);

// Maps
var map = {'key': 'value'};
map['newKey'] = 42;

// Sets
var set = {1, 2, 3};
set.add(3); // doesn't duplicate

// Collection operators
var doubled = list.map((n) => n * 2).toList();
var evens = list.where((n) => n.isEven).toList();

int? nullableInt; // can be null
int nonNullable = 5; // cannot be null

void process(String? input) {
  if (input != null) {
    print(input.length); // safe
  }
  // or use ! (assert non-null) if you're sure
  print(input!.length); // throws if null
}

Future<String> fetchData() async {
  await Future.delayed(Duration(seconds: 2));
  return 'Data loaded';
}

void main() async {
  print('Start');
  String result = await fetchData();
  print(result);
  print('End');
}
